import { task, metadata, wait } from "@trigger.dev/sdk/v3";

const trial_id = "realtime_progress_metadata__KcTsArH";

export const progressTask = task({
  id: `progressTask-${trial_id}`,
  run: async () => {
    const totalItems = 10;

    for (let i = 1; i <= totalItems; i++) {
      // Simulate work
      await wait.for({ seconds: 1 });

      // Calculate completion percentage
      const percentage = Math.round((i / totalItems) * 100);

      // Update progress metadata
      metadata.set("progress", percentage);

      // Append log entry for this item
      const message = `Processed item ${i} of ${totalItems} (${percentage}% complete)`;
      metadata.append("logs", message);
    }

    return {
      status: "completed",
      totalItems,
      message: "All items processed successfully",
    };
  },
});

import { defineConfig } from "@trigger.dev/sdk/v3";

export default defineConfig({
  project: "progress-project",
  dirs: ["./trigger"],
});
